const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();
app.use(helmet());
app.use(express.json({ limit: '1mb' }));

const esClient = new Client({
  node: process.env.ELASTICSEARCH_URL || 'https://localhost:9200',
  auth: {
    apiKey: process.env.ELASTICSEARCH_API_KEY
  },
  tls: {
    rejectUnauthorized: true
  }
});

const ALLOWED_INDICES = new Set([
  'products',
  'users',
  'orders',
  'analytics',
  'logs'
]);

const ADMIN_API_KEYS = new Set(
  (process.env.ADMIN_API_KEYS || '').split(',').filter(Boolean)
);

const searchLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  message: 'Too many requests from this IP'
});

function authenticateAdmin(req, res, next) {
  const apiKey = req.headers['x-api-key'];
  
  if (!apiKey || !ADMIN_API_KEYS.has(apiKey)) {
    return res.status(401).json({ error: 'Unauthorized: Invalid API key' });
  }
  
  next();
}

function validateIndexName(indexName) {
  if (!indexName || typeof indexName !== 'string') {
    return false;
  }
  
  if (!/^[a-z0-9_-]+$/.test(indexName)) {
    return false;
  }
  
  if (!ALLOWED_INDICES.has(indexName)) {
    return false;
  }
  
  return true;
}

function validateQueryDSL(query) {
  if (!query || typeof query !== 'object') {
    return false;
  }
  
  const allowedTopLevelKeys = new Set([
    'query', 'size', 'from', 'sort', '_source', 
    'aggs', 'aggregations', 'highlight', 'fields'
  ]);
  
  for (const key of Object.keys(query)) {
    if (!allowedTopLevelKeys.has(key)) {
      return false;
    }
  }
  
  if (query.size && (typeof query.size !== 'number' || query.size > 1000 || query.size < 0)) {
    return false;
  }
  
  if (query.from && (typeof query.from !== 'number' || query.from > 10000 || query.from < 0)) {
    return false;
  }
  
  const queryString = JSON.stringify(query);
  if (queryString.length > 50000) {
    return false;
  }
  
  const dangerousPatterns = [
    /_update_by_query/i,
    /_delete_by_query/i,
    /script/i,
    /_reindex/i,
    /_bulk/i
  ];
  
  for (const pattern of dangerousPatterns) {
    if (pattern.test(queryString)) {
      return false;
    }
  }
  
  return true;
}

function sanitizeResponse(response) {
  const sanitized = {
    took: response.took,
    timed_out: response.timed_out,
    hits: {
      total: response.hits?.total,
      max_score: response.hits?.max_score,
      hits: response.hits?.hits?.map(hit => ({
        _index: hit._index,
        _id: hit._id,
        _score: hit._score,
        _source: hit._source
      }))
    }
  };
  
  if (response.aggregations) {
    sanitized.aggregations = response.aggregations;
  }
  
  return sanitized;
}

app.post('/api/search/:index', authenticateAdmin, searchLimiter, async (req, res) => {
  try {
    const indexName = req.params.index;
    const queryDSL = req.body.query;
    
    if (!validateIndexName(indexName)) {
      return res.status(400).json({ 
        error: 'Invalid index name. Only allowed indices can be queried.' 
      });
    }
    
    if (!validateQueryDSL(queryDSL)) {
      return res.status(400).json({ 
        error: 'Invalid query DSL. Query contains forbidden operations or exceeds limits.' 
      });
    }
    
    const searchParams = {
      index: indexName,
      body: queryDSL,
      timeout: '30s',
      request_timeout: 30000
    };
    
    const response = await esClient.search(searchParams);
    
    const sanitizedResponse = sanitizeResponse(response);
    
    res.json({
      success: true,
      data: sanitizedResponse
    });
    
  } catch (error) {
    console.error('Search error:', {
      message: error.message,
      index: req.params.index,
      timestamp: new Date().toISOString()
    });
    
    res.status(500).json({ 
      error: 'Search failed',
      message: error.meta?.body?.error?.type || 'Internal server error'
    });
  }
});

app.get('/api/indices', authenticateAdmin, (req, res) => {
  res.json({
    success: true,
    indices: Array.from(ALLOWED_INDICES)
  });
});

app.use((err, req, res, next) => {
  console.error('Unhandled error:', {
    message: err.message,
    timestamp: new Date().toISOString()
  });
  
  res.status(500).json({ 
    error: 'Internal server error' 
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Secure Elasticsearch API running on port ${PORT}`);
});

module.exports = app;